function readOptionalNonEmptyString(
  value: unknown,
  fieldName: string
): { ok: true; value: string | undefined } | { ok: false; message: string } {
  if (value === undefined) {
    return { ok: true, value: undefined };
  }

  if (value === null || typeof value !== "string") {
    return { ok: false, message: `${fieldName} must be a string` };
  }

  const trimmed = value.trim();
  if (!trimmed) {
    return { ok: false, message: `${fieldName} must be a non-empty string` };
  }

  return { ok: true, value: trimmed };
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function parseAuthBody(
  body: AuthBody
): { ok: true; value: { email: string; password: string } } | { ok: false; message: string } {
  const email = readString(body.email)?.toLowerCase();
  const password = readString(body.password);

  if (!email || !isValidEmail(email)) {
    return { ok: false, message: "email must be valid" };
  }

  if (!password || password.length < 8) {
    return { ok: false, message: "password must be at least 8 characters" };
  }

  return { ok: true, value: { email, password } };
}

function parseOptionalFolderId(
  value: unknown,
  userId: number
): { ok: true; value: number | null } | { ok: false; message: string } {
  if (value === undefined || value === null) {
    return { ok: true, value: null };
  }

  if (typeof value !== "number" || !Number.isInteger(value) || value < 1) {
    return { ok: false, message: "folder_id must reference an existing folder" };
  }

  if (!getFolder(value, userId)) {
    return { ok: false, message: "folder_id must reference an existing folder" };
  }

  return { ok: true, value };
}

function validateCreateBookmark(
  body: BookmarkBody,
  userId: number
):
  | {
      ok: true;
      value: {
        url: string;
        title: string;
        description: string | null;
        folder_id: number | null;
      };
    }
  | { ok: false; message: string } {
  const url = readRequiredNonEmptyString(body.url, "url");
  const title = readRequiredNonEmptyString(body.title, "title");
  const description = readString(body.description);
  const folderId = parseOptionalFolderId(body.folder_id, userId);

  if (!url.ok) {
    return url;
  }

  if (!isValidUrl(url.value)) {
    return { ok: false, message: "url must be a valid URL" };
  }

  if (!title.ok) {
    return title;
  }

  if (!folderId.ok) {
    return folderId;
  }

  return {
    ok: true,
    value: {
      url: url.value,
      title: title.value,
      description: description ?? null,
      folder_id: folderId.value,
    },
  };
}

function validateFolderName(
  body: FolderBody
): { ok: true; value: { name: string } } | { ok: false; message: string } {
  const name = readRequiredNonEmptyString(body.name, "name");

  if (!name.ok) {
    return name;
  }

  return { ok: true, value: { name: name.value } };
}

function authenticate(req: Request, res: Response, next: NextFunction) {
  const authorization = req.header("Authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "unauthorized" });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as string | JwtPayloadWithUser;
    const userId =
      typeof decoded === "object" && typeof decoded.userId === "number"
        ? decoded.userId
        : null;

    if (userId === null || !getUser(userId)) {
      return res.status(401).json({ error: "unauthorized" });
    }

    req.userId = userId;
    return next();
  } catch {
    return res.status(401).json({ error: "unauthorized" });
  }
}

